import{_ as e,c as a,o as i,U as t}from"./chunks/framework.9QHaLlVJ.js";const m=JSON.parse('{"title":"CSRF","description":"","frontmatter":{},"headers":[],"relativePath":"doc/网络安全/CSRF/CSRF.md","filePath":"packages/doc/src/网络安全/CSRF/CSRF.md","lastUpdated":1704643216000}'),r={name:"doc/网络安全/CSRF/CSRF.md"},n=t('<h1 id="csrf" tabindex="-1">CSRF <a class="header-anchor" href="#csrf" aria-label="Permalink to &quot;CSRF&quot;">​</a></h1><h2 id="_1-csrf-介绍" tabindex="-1">1.CSRF 介绍 <a class="header-anchor" href="#_1-csrf-介绍" aria-label="Permalink to &quot;1.CSRF 介绍&quot;">​</a></h2><p>CSRF，是跨站请求伪造（Cross Site Request Forgery）的缩写，是一种劫持受信任用户向服务器发送非预期请求的攻击方式。</p><p>通常情况下，CSRF 攻击是攻击者借助受害者的 Cookie 骗取服务器的信任，在受害者毫不知情的情况下以受害者名义伪造请求发送给受攻击服务器，从而在并未授权的情况下执行在权限保护之下的操作。</p><h2 id="_2-csrf-特点" tabindex="-1">2.CSRF 特点 <a class="header-anchor" href="#_2-csrf-特点" aria-label="Permalink to &quot;2.CSRF 特点&quot;">​</a></h2><ul><li>攻击一般发起在第三方网站，而不是被攻击的网站。</li><li>攻击是利用受害者在被攻击网站的登录凭证，冒充受害者提交操作，仅仅是“冒用”，而不是直接窃取数据。</li><li>攻击者预测出被攻击的网站接口的所有参数，成功伪造请求。</li></ul><h2 id="_3-防御方法" tabindex="-1">3.防御方法 <a class="header-anchor" href="#_3-防御方法" aria-label="Permalink to &quot;3.防御方法&quot;">​</a></h2><h3 id="samesite-属性" tabindex="-1">SameSite 属性 <a class="header-anchor" href="#samesite-属性" aria-label="Permalink to &quot;SameSite 属性&quot;">​</a></h3><p>Cookie 的 SameSite 属性用来限制第三方 Cookie，从而减少安全风险，可以用来防止 CSRF 攻击和用户追踪。</p><p>它可以设置三个值。</p><ul><li>Strict</li><li>Lax</li><li>None</li></ul><h4 id="strict" tabindex="-1">Strict <a class="header-anchor" href="#strict" aria-label="Permalink to &quot;Strict&quot;">​</a></h4><p>Strict最为严格，完全禁止第三方 Cookie，跨站点时，任何情况下都不会发送 Cookie。换言之，只有当前网页的 URL 与请求目标一致，才会带上 Cookie。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>Set-Cookie: CookieName=CookieValue; SameSite=Strict;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个规则过于严格，可能造成非常不好的用户体验。比如，当前网页有一个 GitHub 链接，用户点击跳转就不会带有 GitHub 的 Cookie，跳转过去总是未登陆状态。</p><h4 id="lax" tabindex="-1">Lax <a class="header-anchor" href="#lax" aria-label="Permalink to &quot;Lax&quot;">​</a></h4><p>Lax 规则稍稍放宽，大多数情况也是不发送第三方 Cookie，但是导航到目标网址的 Get 请求除外。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>Set-Cookie: CookieName=CookieValue; SameSite=Lax;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Chrome 计划将 Lax 变为默认设置。这时，网站可以选择显式关闭 SameSite 属性，将其设为 None 。不过，前提是必须同时设置 Secure 属性（Cookie 只能通过 HTTPS 协议发送），否则无效。</p><p>下面的设置无效：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>Set-Cookie: widget_session=abc123; SameSite=None</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>下面的设置有效：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>Set-Cookie: widget_session=abc123; SameSite=None; Secure</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>要使用 SameSite 属性，前提是用户浏览器支持 SameSite 属性，可以使用 <a href="https://link.segmentfault.com/?enc=Y4XuG%2F54FlnKIuzPb886Dg%3D%3D.d5TUGs6Vv%2FbLwFMEwCumXDwAIcYloB2L76RiJZvOVp4yE3p%2BWJfucLqWnfIq1kY8" target="_blank" rel="noreferrer">caniuse</a> 查看浏览器对于 SameSite 属性的支持。</p><h3 id="同源检测" tabindex="-1">同源检测 <a class="header-anchor" href="#同源检测" aria-label="Permalink to &quot;同源检测&quot;">​</a></h3><p>在 HTTP 协议中，每一个异步请求都会携带两个 Header ，用于标记来源域名：</p><ul><li>Origin Header</li><li>Referer Header</li></ul><p>这两个 Header 在浏览器发起请求时，大多数情况会自动带上，并且不能由前端自定义内容。 服务器可以通过解析这两个 Header 中的域名，确定请求的来源域。</p><p>通过校验请求的该字段，我们能知道请求是否是从本站发出的。我们可以通过拒绝非本站发出的请求，来避免了 CSRF 攻击。</p><h4 id="验证-origin" tabindex="-1">验证 Origin <a class="header-anchor" href="#验证-origin" aria-label="Permalink to &quot;验证 Origin&quot;">​</a></h4><p>如果 Origin 存在，那么直接使用 Origin 中的字段确认来源域名就可以。</p><p>但是 Origin 在以下两种情况下并不存在：</p><ul><li>1、 IE11同源策略： IE 11 不会在跨站 CORS 请求上添加 Origin 头，Referer 头将仍然是唯一的标识。最根本原因是因为IE 11对同源的定义和其他浏览器有不同，有两个主要的区别，可以参考 <a href="https://link.segmentfault.com/?enc=v6jxS6IgYeENyGSPUvaY%2BQ%3D%3D.jtC0NpZOy8KbUzI4bY3rN3CZKNbcztZ6qXlfUPgtGK3j6VUZu53ps2YEm5D2Nnh7bFCfIRS%2BlheghG6AHk5%2BbReCPZukMEpobxPmw0Jdldw%3D" target="_blank" rel="noreferrer">MDN Same-origin_policy#IE_Exceptions</a></li><li>2、 302重定向： 在302重定向之后 Origin 不包含在重定向的请求中，因为 Origin 可能会被认为是其他来源的敏感信息。对于302重定向的情况来说都是定向到新的服务器上的 URL ，因此浏览器不想将 Origin 泄漏到新的服务器上。</li></ul><h4 id="验证-referer" tabindex="-1">验证 Referer <a class="header-anchor" href="#验证-referer" aria-label="Permalink to &quot;验证 Referer&quot;">​</a></h4><p>如果 Referer 存在，也可以用来确认 HTTP 请求的来源地址。</p><p>需要注意的是在以下情况下 Referer 没有或者不可信：</p><ul><li>1.IE6、7下使用<code>window.location.href=url</code>进行界面的跳转，会丢失 Referer。</li><li>2.IE6、7下使用<code>window.open</code>，也会缺失 Referer。</li><li>3.HTTPS 页面跳转到 HTTP 页面，所有浏览器 Referer 都丢失。</li><li>4.点击 Flash 上到达另外一个网站的时候，Referer 的情况就比较杂乱，不太可信。</li></ul><p>总的来说，同源检测是一个相对简单的防范方法，能够防范绝大多数的 CSRF 攻击，但这并不是万无一失的，对于安全性要求较高，或者有较多用户输入内容的网站，我们就要对关键的接口做额外的防护措施。</p><h3 id="验证码" tabindex="-1">验证码 <a class="header-anchor" href="#验证码" aria-label="Permalink to &quot;验证码&quot;">​</a></h3><p>验证码的种类有很多，比如图形验证码，基于人机之间知识差异的验证码，行为式验证码。</p><p>CSRF 攻击往往是在用户不知情的情况下成功伪造请求。而验证码会强制用户必须与应用进行交互，才能完成最终请求，而且因为 CSRF 攻击无法获取到验证码，因此通常情况下，验证码能够很好地遏制 CSRF 攻击。 但验证码并不是万能的，因为出于用户体验考虑，不能给网站所有的操作都加上验证码。因此，验证码只能作为防御 CSRF 的一种辅助手段，而不能作为最主要的解决方案。</p><h3 id="添加-token-验证" tabindex="-1">添加 Token 验证 <a class="header-anchor" href="#添加-token-验证" aria-label="Permalink to &quot;添加 Token 验证&quot;">​</a></h3><p>CSRF 攻击之所以能够成功，是因为攻击者可以完全伪造用户的请求，该请求中所有的用户验证信息都是存在于 Cookie 中，因此攻击者可以在不知道这些验证信息的情况下直接利用用户自己的 Cookie 来通过安全验证。 要抵御 CSRF，关键在于在请求中放入攻击者所不能伪造的信息，并且该信息不存在于 Cookie 之中。可以在 HTTP 请求中以参数的形式加入一个随机产生的 Token，并在服务器端建立一个拦截器来验证这个 Token，如果请求中没有 Token 或者 Token 内容不正确，则认为可能是 CSRF 攻击而拒绝该请求。</p><h4 id="添加-token-验证的步骤" tabindex="-1">添加 Token 验证的步骤： <a class="header-anchor" href="#添加-token-验证的步骤" aria-label="Permalink to &quot;添加 Token 验证的步骤：&quot;">​</a></h4><p><strong>1、服务器将 Token 返回到前端</strong> 用户打开页面时，前端发起请求，服务器会返回一个 Token，该 Token 通过加密算法对数据进行加密，一般 Token 都包括随机字符串和时间戳的组合，同时 Token 会存在服务器的 Session 中。之后页面加载完成时，使用 JS 遍历整个 DOM 树，在 DOM 中所有地址是本站的 <code>a</code> 和 <code>form</code> 标签中加入 Token，其他的请求就在编码时手动添加 Token 这个参数。</p><p><strong>2、前端发请求时携带这个 Token</strong> 对于 GET 请求，Token 将附在请求地址之后，这样 URL 就变成 <code>http://url?token=tokenvalue</code>。 而对于 <code>form</code> 标签发起的 POST 请求来说，要在 <code>form</code> 的最后加上：</p><div class="language-xml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">input</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=”hidden” </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=”token” </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=”tokenvalue”/&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>总之，就是前端发请求时把 Token 以参数的形式加入请求中。</p><p><strong>3、服务器验证 Token 是否正确</strong> 当前端得到了 Token ，再次提交给服务器的时候，服务器需要判断 Token 的有效性，验证过程是先解密 Token，对比加密字符串以及时间戳，如果加密字符串一致且时间未过期，那么这个 Token 就是有效的。</p><h2 id="_3-总结" tabindex="-1">3.总结 <a class="header-anchor" href="#_3-总结" aria-label="Permalink to &quot;3.总结&quot;">​</a></h2><p>CSRF能够攻击成功的本质是：重要操作的所有参数都是可以被攻击者猜测到的。 所以只要防止攻击者成功的构造一个伪造请求，就可以杜绝攻击了！</p><h2 id="案例" tabindex="-1">案例 <a class="header-anchor" href="#案例" aria-label="Permalink to &quot;案例&quot;">​</a></h2><p><a href="https://link.segmentfault.com/?enc=kclmGdE3x2iiP4EMC4VFsQ%3D%3D.qOm0cxIVCHmH%2B5pPJ6IYJ%2B5mntg%2Bri4mbiaO1wtj3CPbtG%2FuN4Qo9yaUMx3D7FXu" target="_blank" rel="noreferrer">希尔顿酒店官网的CSRF漏洞</a></p><p><a href="https://link.segmentfault.com/?enc=kqjcQqn0ZFiyJDrUqWrP5w%3D%3D.udsbgf18Ldyp9zL%2BfCKiOYGWNR%2FqXxCRtED7o%2BKrSCRAQsUitYD8%2BXCaQAwgO0%2BJRaNwC9DGUD5JSmKQ0BWBTRhckufiNQE4HdNL4xuc05HujPprghO1r7RbZbs26psvDqQ%2FNALBh8wCk4j12S2cVwMbAdQKdS7kDPJOIqr8HlEednvUKmDi%2B6BABb%2Bk4EOLraXw3j%2Fax%2F0ZEh98E5iEUMF2uWPkdmM%2FRvhcCRYWeYS7yFhQhPSVasgtVVD9WEIRkXc2CAGIdAHsaQJKzIipY4h7JxWe%2FOlOFU0%2FYm6uHAG1VTRByDgHgatq9hgdBrDHy8%2FYQq7QSODnMSMDnOS3NMAhBuYDxfds9diszkPHK4yv46VZtQMaJz46H0tN9H1q4oDGJipR8ieET1wa9yjfQ7qvw7XRdDqJLlxSTTaA%2FK1jQruRFjbU8eAy2TFpVUTxe3Ax53ccnfur5%2FLtIctP3GCsyv4rKI5My3%2B9Zj376ro5%2BvNr8HwP3pjNKBH46%2Bq5DsTvA9GsdY6U6wprzMWw%2BkklW%2BJQESNxqT7M0GW60jMMl5fuz6jqVFxtd13Y0kvyamVLDJF5i25HvgqvVYRFnvMhz4GJjs9UjrcBXVab9Hc%3D" target="_blank" rel="noreferrer">新浪微博CSRF漏洞</a></p><p><a href="https://link.segmentfault.com/?enc=DqR1xNyiT7OGEbMhCZKYoQ%3D%3D.cZ%2BqC9k3hHEk1tV3hq1H5pzINoW3e1k8e%2B%2FAAkoBHcGi7SJhqMetguyYu5dNDzYcdXDJPxa3mBKAC2c2oakixA%3D%3D" target="_blank" rel="noreferrer">WordPress的CSRF漏洞</a></p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><p><a href="https://link.segmentfault.com/?enc=j4QbIYAYd7Wnwqape1ywBw%3D%3D.GdR2WbWn2xHCWlgGmKxtfRi77UMwv5h%2BYyYA2sfm3Afb%2FOqH5v%2ByIIOLok9YdEA9NupDtOS37jFmbWDbLzfd0g%3D%3D" target="_blank" rel="noreferrer">HTTP cookies</a></p><p><a href="https://link.segmentfault.com/?enc=psW%2BOjQ2lMDjxY69DHvSeg%3D%3D.ESXiDflZZPZvPdMwvsM%2Buugl9Hf1CTh3adTBdDXRCRM0SjGRpF2iNWTAo4tqmUAIKk%2Foe6CC8gFoqgBumDo9MQ%3D%3D" target="_blank" rel="noreferrer">Cookie 的 SameSite 属性</a></p><p><a href="https://link.segmentfault.com/?enc=VxFLKJbajyrkhlm9vsw%2FHQ%3D%3D.CHtMuyeKxu2607uxWyi9VbSGzmamgxBnaW%2FY6KQbQtm17%2FKhomWhviiQeGIdb1CQug1Fz8wR%2FZTVTwY7o0%2BzpxKuDEUBBHLqG9CY0k7zXO8%3D" target="_blank" rel="noreferrer">CSRF漏洞的原理</a></p><p><a href="https://segmentfault.com/a/1190000006944760" target="_blank" rel="noreferrer">前后端分离架构下CSRF防御机制</a></p><p><a href="https://link.segmentfault.com/?enc=wb3dqBB36jHDApyNTX%2FY%2BQ%3D%3D.nRFcnlOgX0bFZTQzw7%2BF1LpOHc80HrN2NMMHDXZmjMdlnhgbAnaNtQIDuhGKod0Y" target="_blank" rel="noreferrer">前端安全系列之二：如何防止CSRF攻击？</a></p><p><a href="https://link.segmentfault.com/?enc=zKE3t9qI1chnYdleZ8UHXg%3D%3D.qrI%2FWhTs8zYz8OLiT7Xa1cPMjdeXMOPM6pkO%2Bau85TkrXk6P87vq5Zkmeb8cmSP5bYCg%2BuZFC1Na2Cwt26%2FrEw%3D%3D" target="_blank" rel="noreferrer">CSRF 攻击的应对之道</a></p>',62),s=[n];function o(l,p,h,d,c,k){return i(),a("div",null,s)}const b=e(r,[["render",o]]);export{m as __pageData,b as default};
